<?php require_once __DIR__.'/../includes/functions.php'; require_once __DIR__.'/../includes/db.php'; require_admin(); $pdo=db(); if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ if(($_POST['action']??'')==='delete'){ $pdo->prepare('DELETE FROM packages WHERE id=?')->execute([(int)$_POST['id']]); } else { $data=[post_value('title'),post_value('subtitle'),post_value('original_price'),post_value('discounted_price'),post_value('details'),post_value('badge'),post_value('status')==='inactive'?'inactive':'active',(int)post_value('sort_order')]; if(!empty($_POST['id'])){ $data[]=(int)$_POST['id']; $pdo->prepare('UPDATE packages SET title=?,subtitle=?,original_price=?,discounted_price=?,details=?,badge=?,status=?,sort_order=? WHERE id=?')->execute($data); } else { $pdo->prepare('INSERT INTO packages (title,subtitle,original_price,discounted_price,details,badge,status,sort_order) VALUES (?,?,?,?,?,?,?,?)')->execute($data); } } redirect('packages.php'); } include 'partials/header.php'; include 'partials/sidebar.php'; $rows=$pdo->query('SELECT * FROM packages ORDER BY sort_order,id')->fetchAll(); ?><h2 class="mb-4 text-3xl font-black">Manage Packages</h2><form method="post" class="mb-6 grid gap-3 rounded-2xl bg-white p-5 shadow md:grid-cols-2"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input name="title" required class="rounded border p-3" placeholder="Package title"><input name="subtitle" class="rounded border p-3" placeholder="Subtitle"><input name="original_price" class="rounded border p-3" placeholder="Original price"><input name="discounted_price" required class="rounded border p-3" placeholder="Final / discounted price"><input name="badge" class="rounded border p-3" placeholder="Badge"><input type="number" name="sort_order" value="0" class="rounded border p-3" placeholder="Sort order"><select name="status" class="rounded border p-3"><option value="active">active</option><option value="inactive">inactive</option></select><textarea name="details" class="rounded border p-3 md:col-span-2" placeholder="Detailed SEO-friendly package description"></textarea><button class="rounded bg-slate-950 px-5 py-3 font-bold text-white md:col-span-2">Add Package</button></form><div class="grid gap-4"><?php foreach($rows as $r):?><form method="post" class="grid gap-2 rounded-2xl bg-white p-4 shadow md:grid-cols-4"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="id" value="<?=e($r['id'])?>"><input name="title" value="<?=e($r['title'])?>" class="rounded border p-2"><input name="subtitle" value="<?=e($r['subtitle'])?>" class="rounded border p-2"><input name="original_price" value="<?=e($r['original_price'])?>" class="rounded border p-2"><input name="discounted_price" value="<?=e($r['discounted_price'])?>" class="rounded border p-2"><input name="badge" value="<?=e($r['badge'])?>" class="rounded border p-2"><input type="number" name="sort_order" value="<?=e($r['sort_order'])?>" class="rounded border p-2"><select name="status" class="rounded border p-2"><option <?=$r['status']==='active'?'selected':''?>>active</option><option <?=$r['status']==='inactive'?'selected':''?>>inactive</option></select><textarea name="details" class="rounded border p-2 md:col-span-4"><?=e($r['details'])?></textarea><button class="rounded bg-blue-950 px-4 py-2 font-bold text-white">Update</button><button name="action" value="delete" onclick="return confirm('Delete this package?')" class="rounded bg-red-700 px-4 py-2 font-bold text-white">Remove</button></form><?php endforeach;?></div><?php include 'partials/footer.php'; ?>
